INSERT INTO `analisis_impacto_regulatorio` VALUES (29,45,'AIR-DEMO-45-001','El proceso de licenciamiento comercial en La Paz presenta tiempos de hasta 10 días hábiles y requiere hasta 6 documentos, generando una carga burocrática significativa que inhibe la apertura de negocios formales.','Reducir el tiempo de resolución a 5 días hábiles, eliminar 2 requisitos sin sustento jurídico y digitalizar la solicitud inicial para permitir su presentación en línea sin necesidad de acudir a ventanilla.','Alternativa 1 (seleccionada): Reforma reglamentaria con digitalización del proceso. Alternativa 2: Circular administrativa interna sin reforma. Alternativa 3: Ventanilla digital sin modificar el reglamento. Se selecciona la Alternativa 1 por su impacto estructural y sustentabilidad a largo plazo.','Desarrollo del módulo digital de solicitudes: $85,000 MXN. Capacitación de 12 funcionarios de ventanilla: $12,000 MXN. Campaña de difusión ciudadana: $8,000 MXN. Total estimado: $105,000 MXN.','Reducción del CBT de $15,574 a $8,200 por trámite (ahorro de $7,374 por licencia). Ahorro ciudadano anual estimado: $13.6 millones MXN para 1,850 trámites anuales. Incremento estimado del 12% en la formalización de negocios.','Impacto directo sobre 1,850 establecimientos comerciales anuales. Beneficio secundario para sus empleados, proveedores y la cadena económica municipal.',1,NULL,NULL,NULL,'Municipal','Consulta pública realizada del 15 al 30 de abril 2026 mediante plataforma digital y presencial. Se recibieron 43 comentarios ciudadanos y 7 de cámaras empresariales (CANACO, COPARMEX). El 78% apoya la reforma.',NULL,NULL,'borrador','pendiente',NULL,NULL,1,'2026-06-07 04:43:14','2026-06-17 04:43:14',NULL),(30,47,'AIR-DEMO-47-001','El proceso de licenciamiento comercial en La Paz presenta tiempos de hasta 10 días hábiles y requiere hasta 6 documentos, generando una carga burocrática significativa que inhibe la apertura de negocios formales.','Reducir el tiempo de resolución a 5 días hábiles, eliminar 2 requisitos sin sustento jurídico y digitalizar la solicitud inicial para permitir su presentación en línea sin necesidad de acudir a ventanilla.','Alternativa 1 (seleccionada): Reforma reglamentaria con digitalización del proceso. Alternativa 2: Circular administrativa interna sin reforma. Alternativa 3: Ventanilla digital sin modificar el reglamento. Se selecciona la Alternativa 1 por su impacto estructural y sustentabilidad a largo plazo.','Desarrollo del módulo digital de solicitudes: $85,000 MXN. Capacitación de 12 funcionarios de ventanilla: $12,000 MXN. Campaña de difusión ciudadana: $8,000 MXN. Total estimado: $105,000 MXN.','Reducción del CBT de $15,574 a $8,200 por trámite (ahorro de $7,374 por licencia). Ahorro ciudadano anual estimado: $13.6 millones MXN para 1,850 trámites anuales. Incremento estimado del 12% en la formalización de negocios.','Impacto directo sobre 1,850 establecimientos comerciales anuales. Beneficio secundario para sus empleados, proveedores y la cadena económica municipal.',1,NULL,NULL,NULL,'Municipal','Consulta pública realizada del 15 al 30 de abril 2026 mediante plataforma digital y presencial. Se recibieron 43 comentarios ciudadanos y 7 de cámaras empresariales (CANACO, COPARMEX). El 78% apoya la reforma.',NULL,NULL,'borrador','pendiente',NULL,NULL,1,'2026-06-07 04:43:14','2026-06-17 04:43:14',NULL),(31,49,'AIR-DEMO-49-001','El proceso de licenciamiento comercial en La Paz presenta tiempos de hasta 10 días hábiles y requiere hasta 6 documentos, generando una carga burocrática significativa que inhibe la apertura de negocios formales.','Reducir el tiempo de resolución a 5 días hábiles, eliminar 2 requisitos sin sustento jurídico y digitalizar la solicitud inicial para permitir su presentación en línea sin necesidad de acudir a ventanilla.','Alternativa 1 (seleccionada): Reforma reglamentaria con digitalización del proceso. Alternativa 2: Circular administrativa interna sin reforma. Alternativa 3: Ventanilla digital sin modificar el reglamento. Se selecciona la Alternativa 1 por su impacto estructural y sustentabilidad a largo plazo.','Desarrollo del módulo digital de solicitudes: $85,000 MXN. Capacitación de 12 funcionarios de ventanilla: $12,000 MXN. Campaña de difusión ciudadana: $8,000 MXN. Total estimado: $105,000 MXN.','Reducción del CBT de $15,574 a $8,200 por trámite (ahorro de $7,374 por licencia). Ahorro ciudadano anual estimado: $13.6 millones MXN para 1,850 trámites anuales. Incremento estimado del 12% en la formalización de negocios.','Impacto directo sobre 1,850 establecimientos comerciales anuales. Beneficio secundario para sus empleados, proveedores y la cadena económica municipal.',1,NULL,NULL,NULL,'Municipal','Consulta pública realizada del 15 al 30 de abril 2026 mediante plataforma digital y presencial. Se recibieron 43 comentarios ciudadanos y 7 de cámaras empresariales (CANACO, COPARMEX). El 78% apoya la reforma.',NULL,NULL,'borrador','pendiente',NULL,NULL,1,'2026-06-07 04:43:15','2026-06-17 04:43:15',NULL),(32,51,'AIR-DEMO-51-001','El proceso de licenciamiento comercial en La Paz presenta tiempos de hasta 10 días hábiles y requiere hasta 6 documentos, generando una carga burocrática significativa que inhibe la apertura de negocios formales.','Reducir el tiempo de resolución a 5 días hábiles, eliminar 2 requisitos sin sustento jurídico y digitalizar la solicitud inicial para permitir su presentación en línea sin necesidad de acudir a ventanilla.','Alternativa 1 (seleccionada): Reforma reglamentaria con digitalización del proceso. Alternativa 2: Circular administrativa interna sin reforma. Alternativa 3: Ventanilla digital sin modificar el reglamento. Se selecciona la Alternativa 1 por su impacto estructural y sustentabilidad a largo plazo.','Desarrollo del módulo digital de solicitudes: $85,000 MXN. Capacitación de 12 funcionarios de ventanilla: $12,000 MXN. Campaña de difusión ciudadana: $8,000 MXN. Total estimado: $105,000 MXN.','Reducción del CBT de $15,574 a $8,200 por trámite (ahorro de $7,374 por licencia). Ahorro ciudadano anual estimado: $13.6 millones MXN para 1,850 trámites anuales. Incremento estimado del 12% en la formalización de negocios.','Impacto directo sobre 1,850 establecimientos comerciales anuales. Beneficio secundario para sus empleados, proveedores y la cadena económica municipal.',1,NULL,NULL,NULL,'Municipal','Consulta pública realizada del 15 al 30 de abril 2026 mediante plataforma digital y presencial. Se recibieron 43 comentarios ciudadanos y 7 de cámaras empresariales (CANACO, COPARMEX). El 78% apoya la reforma.',NULL,NULL,'borrador','pendiente',NULL,NULL,1,'2026-06-07 04:43:15','2026-06-17 04:43:15',NULL),(33,53,'LPZ-AIR-DGGD-2026-001','El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\r\nIngredientes (para 6 porciones)\r\n500 g de maíz pozolero precocido\r\n1 kg de carne de cerdo (espinazo o maciza)\r\n500 g de costilla de cerdo\r\n1 cebolla blanca entera\r\n5 dientes de ajo\r\n2 hojas de laurel\r\nSal al gusto\r\nPara la salsa roja:\r\n6 chiles guajillo\r\n4 chiles anchos\r\n1 diente de ajo\r\n¼ de cebolla\r\n1 cucharadita de orégano seco\r\nSal al gusto\r\nPara acompañar:\r\nLechuga picada\r\nRábanos en rodajas\r\nCebolla picada\r\nLimón\r\nOrégano seco\r\nChile piquín\r\nTostadas, crema o queso al gusto\r\nPreparación\r\nCocer el maíz: Lava el maíz pozolero y colócalo en una olla grande. Cúbrelo con agua y cocina a fuego medio hasta que reviente y esté suave, aproximadamente 1 hora \r\nMDZ Online\r\nMDZ Online\r\n.\r\nCocer la carne: En otra olla grande, coloca la carne de cerdo, costilla, cebolla entera, ajo y hojas de laurel. Cubre con agua y hierve durante 1 hora o hasta que la carne esté muy suave \r\nMDZ Online\r\nMDZ Online\r\n. Retira la cebolla y los ajos, añade sal al gusto y deshebra la carne si lo deseas.\r\nPreparar la salsa roja: Desvena y tuesta los chiles guajillo y ancho en un comal seco por unos segundos. Remójalos en agua caliente 15-20 minutos hasta que se ablanden. Licúa los chiles con un diente de ajo, ¼ de cebolla, orégano y un poco del agua de remojo. Cuela la salsa para eliminar restos de piel y semillas \r\nMDZ Online\r\nMDZ Online\r\n.\r\nIntegrar la salsa al caldo: En una olla grande, calienta un poco de aceite y fríe la salsa colada durante 5 minutos moviéndola constantemente. Añade el caldo de la carne y mezcla bien. Incorpora la carne deshebrada y el maíz cocido. Cocina a fuego bajo 20-30 minutos para que los sabores se integren \r\nchefgoya.com\r\nchefgoya.com\r\n+1\r\n.\r\nServir: Sirve el pozole caliente y acompaña con lechuga, rábanos, cebolla, limón, orégano y chile piquín al gusto. Puedes ofrecer tostadas, crema o queso Cotija para complementar \r\nRecetas Nestlé\r\nRecetas Nestlé\r\n+1\r\n.\r\nConsejos adicionales\r\nPara un sabor más auténtico, utiliza maíz cacahuazintle y carne de cabeza de cerdo si está disponible \r\nchefgoya.com\r\nchefgoya.com\r\n.\r\nPuedes sustituir parte de la carne de cerdo por pollo o pavo para una versión más ligera \r\nmexicoenmicocina.com\r\nmexicoenmicocina.com\r\n.\r\nLa preparación requiere paciencia, especialmente para que el caldo adquiera un color rojo profundo y un sabor equilibrado entre maíz, carne y chiles \r\nMDZ Online\r\nMDZ Online\r\n.\r\nEste pozole rojo es ideal para celebraciones, reuniones familiares o cualquier ocasión especial, y cada comensal puede personalizarlo con sus guarniciones favoritas para disfrutar de un platillo tradicional mexicano lleno de sabor y tradición \r\nMDZ Online\r\nMDZ Online\r\n.','El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\r\nIngredientes (para 6 porciones)\r\n500 g de maíz pozolero precocido\r\n1 kg de carne de cerdo (espinazo o maciza)\r\n500 g de costilla de cerdo\r\n1 cebolla blanca entera\r\n5 dientes de ajo\r\n2 hojas de laurel\r\nSal al gusto\r\nPara la salsa roja:\r\n6 chiles guajillo\r\n4 chiles anchos\r\n1 diente de ajo\r\n¼ de cebolla\r\n1 cucharadita de orégano seco\r\nSal al gusto','El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\r\nIngredientes (para 6 porciones)\r\n500 g de maíz pozolero precocido\r\n1 kg de carne de cerdo (espinazo o maciza)\r\n500 g de costilla de cerdo\r\n1 cebolla blanca entera\r\n5 dientes de ajo\r\n2 hojas de laurel\r\nSal al gusto\r\nPara la salsa roja:\r\n6 chiles guajillo\r\n4 chiles anchos\r\n1 diente de ajo\r\n¼ de cebolla\r\n1 cucharadita de orégano seco\r\nSal al gusto','El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\r\nIngredientes (para 6 porciones)\r\n500 g de maíz pozolero precocido\r\n1 kg de carne de cerdo (espinazo o maciza)\r\n500 g de costilla de cerdo\r\n1 cebolla blanca entera\r\n5 dientes de ajo\r\n2 hojas de laurel\r\nSal al gusto\r\nPara la salsa roja:\r\n6 chiles guajillo\r\n4 chiles anchos\r\n1 diente de ajo\r\n¼ de cebolla\r\n1 cucharadita de orégano seco\r\nSal al gusto','El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\r\nIngredientes (para 6 porciones)\r\n500 g de maíz pozolero precocido\r\n1 kg de carne de cerdo (espinazo o maciza)\r\n500 g de costilla de cerdo\r\n1 cebolla blanca entera\r\n5 dientes de ajo\r\n2 hojas de laurel\r\nSal al gusto\r\nPara la salsa roja:\r\n6 chiles guajillo\r\n4 chiles anchos\r\n1 diente de ajo\r\n¼ de cebolla\r\n1 cucharadita de orégano seco\r\nSal al gusto','EEl pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles gua