DROP TABLE IF EXISTS `hitos_agenda`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `hitos_agenda` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `accion_agenda_id` bigint unsigned NOT NULL,
  `orden` tinyint unsigned NOT NULL DEFAULT '1',
  `clave` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `nombre` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `completado` tinyint(1) NOT NULL DEFAULT '0',
  `fecha_completado` date DEFAULT NULL,
  `completado_por` bigint unsigned DEFAULT NULL,
  `evidencia_archivo` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `evidencia_nombre` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estado_aprobacion` enum('sin_evidencia','pendiente','aprobado','rechazado') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'sin_evidencia',
  `aprobado_por` bigint unsigned DEFAULT NULL,
  `fecha_aprobacion` date DEFAULT NULL,
  `motivo_rechazo` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `hitos_agenda_completado_por_foreign` (`completado_por`),
  KEY `hitos_agenda_accion_agenda_id_orden_index` (`accion_agenda_id`,`orden`),
  KEY `hitos_agenda_aprobado_por_foreign` (`aprobado_por`),
  CONSTRAINT `hitos_agenda_accion_agenda_id_foreign` FOREIGN KEY (`accion_agenda_id`) REFERENCES `acciones_agenda` (`id`) ON DELETE CASCADE,
  CONSTRAINT `hitos_agenda_aprobado_por_foreign` FOREIGN KEY (`aprobado_por`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `hitos_agenda_completado_por_foreign` FOREIGN KEY (`completado_por`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=361 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

