INSERT INTO `propuestas_regulatorias` VALUES (45,'PROP-DEMO-3-001','[DEMO] Reforma al Reglamento de Comercio — Simplificación de Licencias','Reforma reglamentaria',3,NULL,NULL,'2026-08-21','La tramitología actual representa una barrera para la apertura de negocios. Se propone reducir requisitos, digitalizar el proceso y reducir el plazo de resolución.',NULL,NULL,1,1,1,'requiere_air','consulta',NULL,1,'2026-06-02 04:43:14','2026-06-17 04:43:14'),(46,'PROP-DEMO-3-002','[DEMO] Nueva Norma de Imagen Urbana para Anuncios Publicitarios','Norma municipal',3,NULL,NULL,'2026-10-21','La proliferación de anuncios sin regulación afecta la imagen urbana del centro histórico y la zona turística del Malecón de La Paz.',NULL,NULL,0,1,1,'exento','borrador',NULL,1,'2026-06-02 04:43:14','2026-06-17 04:43:14'),(47,'PROP-DEMO-11-001','[DEMO] Reforma al Reglamento de Comercio — Simplificación de Licencias','Reforma reglamentaria',11,NULL,NULL,'2026-08-21','La tramitología actual representa una barrera para la apertura de negocios. Se propone reducir requisitos, digitalizar el proceso y reducir el plazo de resolución.',NULL,NULL,1,1,1,'requiere_air','consulta',NULL,1,'2026-06-02 04:43:14','2026-06-17 04:43:14'),(48,'PROP-DEMO-11-002','[DEMO] Nueva Norma de Imagen Urbana para Anuncios Publicitarios','Norma municipal',11,NULL,NULL,'2026-10-21','La proliferación de anuncios sin regulación afecta la imagen urbana del centro histórico y la zona turística del Malecón de La Paz.',NULL,NULL,0,1,1,'exento','borrador',NULL,1,'2026-06-02 04:43:14','2026-06-17 04:43:14'),(49,'PROP-DEMO-14-001','[DEMO] Reforma al Reglamento de Comercio — Simplificación de Licencias','Reforma reglamentaria',14,NULL,NULL,'2026-08-21','La tramitología actual representa una barrera para la apertura de negocios. Se propone reducir requisitos, digitalizar el proceso y reducir el plazo de resolución.',NULL,NULL,1,1,1,'requiere_air','consulta',NULL,1,'2026-06-02 04:43:15','2026-06-17 04:43:15'),(50,'PROP-DEMO-14-002','[DEMO] Nueva Norma de Imagen Urbana para Anuncios Publicitarios','Norma municipal',14,NULL,NULL,'2026-10-21','La proliferación de anuncios sin regulación afecta la imagen urbana del centro histórico y la zona turística del Malecón de La Paz.',NULL,NULL,0,1,1,'exento','borrador',NULL,1,'2026-06-02 04:43:15','2026-06-17 04:43:15'),(51,'PROP-DEMO-15-001','[DEMO] Reforma al Reglamento de Comercio — Simplificación de Licencias','Reforma reglamentaria',15,NULL,NULL,'2026-08-21','La tramitología actual representa una barrera para la apertura de negocios. Se propone reducir requisitos, digitalizar el proceso y reducir el plazo de resolución.',NULL,NULL,1,1,1,'requiere_air','consulta',NULL,1,'2026-06-02 04:43:15','2026-06-17 04:43:15'),(52,'PROP-DEMO-15-002','[DEMO] Nueva Norma de Imagen Urbana para Anuncios Publicitarios','Norma municipal',15,NULL,NULL,'2026-10-21','La proliferación de anuncios sin regulación afecta la imagen urbana del centro histórico y la zona turística del Malecón de La Paz.',NULL,NULL,0,1,1,'exento','borrador',NULL,1,'2026-06-02 04:43:15','2026-06-17 04:43:15'),(53,NULL,'Reglamento de Comercio Ambulante del Municipio de La Paz, B.C.S.','Reglamento',11,NULL,NULL,'2026-09-22','{\"responsable_nombre\":\"Carlos Méndez Ruizmmmmmmm\",\"responsable_cargo\":\"Enlace de Simplificación\",\"materia\":\"Comercio\",\"sectores_impactados\":\"Comercio informal, vendedores ambulantes, tianguistas, mercados sobre ruedas, ciudadanía consumidora\",\"justificacion\":\"El municipio carece de un instrumento normativo actualizado que regule de manera integral la actividad comercial en vía pública. El reglamento vigente data de 2008 y no contempla las modalidades actuales de comercio ambulante ni los criterios de ordenamiento territorial.\",\"problematica\":\"Existe una proliferación desordenada de puestos ambulantes en zonas turísticas y comerciales que genera conflictos viales, problemas de higiene y competencia desleal con el comercio establecido. La falta de regulación actualizada impide al municipio ordenar esta actividad de manera efectiva.\",\"alternativas\":\"Se evaluaron tres alternativas: 1) Campaña voluntaria de reordenamiento (descartada por falta de mecanismos de cumplimiento), 2) Acuerdo con cámaras de comercio para autorregulación (insuficiente cobertura), 3) Emisión de reglamento municipal (seleccionada por dar certeza jurídica a todas las partes).\",\"beneficios\":\"Ordenamiento del comercio en vía pública, reducción de conflictos viales, mejora de imagen urbana en zonas turísticas, certeza jurídica para vendedores ambulantes, recaudación por permisos.\",\"costos_burocraticos\":\"Se crearán dos trámites nuevos: Permiso de Comercio Ambulante (anual) y Constancia de Ubicación Autorizada. Se estima un costo de $350 por permiso anual.\",\"tramites_impacta\":null,\"acciones_simplificacion\":{\"Reducción de requisitos\":\"Eliminar la constancia de domicilio y aceptar la credencial de elector como comprobante único.\",\"Fusión de trámites y\\/o modalidades\":\"Unificar el permiso actual de venta en vía pública con el nuevo permiso de comercio ambulante, eliminando la duplicidad de trámites.\"},\"acciones_digitalizacion\":{\"Eliminación de requisitos\":\"El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\\r\\nIngredientes (para 6 porciones)\\r\\n500 g de maíz pozolero precocido\\r\\n1 kg de carne de cerdo (espinazo o maciza)\\r\\n500 g de costilla de cerdo\\r\\n1 cebolla blanca entera\\r\\n5 dientes de ajo\\r\\n2 hojas de laurel\\r\\nSal al gusto\\r\\nPara la salsa roja:\\r\\n6 chiles guajillo\\r\\n4 chiles anchos\\r\\n1 diente de ajo\\r\\n¼ de cebolla\\r\\n1 cucharadita de orégano seco\\r\\nSal al gusto\\r\\nPara acompañar:\\r\\nLechuga picada\\r\\nRábanos en rodajas\\r\\nCebolla picada\\r\\nLimón\\r\\nOrégano seco\\r\\nChile piquín\\r\\nTostadas, crema o queso al gusto\\r\\nPreparación\\r\\nCocer el maíz: Lava el maíz pozolero y colócalo en una olla grande. Cúbrelo con agua y cocina a fuego medio hasta que reviente y esté suave, aproximadamente 1 hora \\r\\nMDZ Online\\r\\nMDZ Online\\r\\n.\\r\\nCocer la carne: En otra olla grande, coloca la carne de cerdo, costilla, cebolla entera, ajo y hojas de laurel. Cubre con agua y hierve durante 1 hora o hasta que la carne esté muy suave \\r\\nMDZ Online\\r\\nMDZ Online\\r\\n. Retira la cebolla y los ajos, añade sal al gusto y deshebra la carne si lo deseas.\\r\\nPreparar la salsa roja: Desvena y tuesta los chiles guajillo y ancho en un comal seco por unos segundos. Remójalos en agua caliente 15-20 minutos hasta que se ablanden. Licúa los chiles con un diente de ajo, ¼ de cebolla, orégano y un poco del agua de remojo. Cuela la salsa para eliminar restos de piel y semillas \\r\\nMDZ Online\\r\\nMDZ Online\\r\\n.\\r\\nIntegrar la salsa al caldo: En una olla grande, calienta un poco de aceite y fríe la salsa colada durante 5 minutos moviéndola constantemente. Añade el caldo de la carne y mezcla bien. Incorpora la carne deshebrada y el maíz cocido. Cocina a fuego bajo 20-30 minutos para que los sabores se integren \\r\\nchefgoya.com\\r\\nchefgoya.com\\r\\n+1\\r\\n.\\r\\nServir: Sirve el pozole caliente y acompaña con lechuga, rábanos, cebolla, limón, orégano y chile piquín al gusto. Puedes ofrecer tostadas, crema o queso Cotija para complementar \\r\\nRecetas Nestlé\\r\\nRecetas Nestlé\\r\\n+1\\r\\n.\\r\\nConsejos adicionales\\r\\nPara un sabor más auténtico, utiliza maíz cacahuazintle y carne de cabeza de cerdo si está disponible \\r\\nchefgoya.com\\r\\nchefgoya.com\\r\\n.\\r\\nPuedes sustituir parte de la carne de cerdo por pollo o pavo para una versión más ligera \\r\\nmexicoenmicocina.com\\r\\nmexicoenmicocina.com\\r\\n.\\r\\nLa preparación requiere paciencia, especialmente para que el caldo adquiera un color rojo profundo y un sabor equilibrado entre maíz, carne y chiles \\r\\nMDZ Online\\r\\nMDZ Online\\r\\n.\\r\\nEste pozole rojo es ideal para celebraciones, reuniones familiares o cualquier ocasión especial, y cada comensal puede personalizarlo con sus guarniciones favoritas para disfrutar de un platillo tradicional mexicano lleno de sabor y tradición \\r\\nMDZ Online\\r\\nMDZ Online\\r\\n.\",\"Mejorar experiencia de usuario\":\"Habilitar solicitud en línea del permiso anual y mapa digital de ubicaciones autorizadas consultable por la ciudadanía.\"},\"fundamento_juridico\":\"Art. 115 fracc. II Constitución Política de los Estados Unidos Mexicanos; Art. 42 fracc. VI Ley Orgánica del Municipio Libre del Estado de B.C.S.; Art. 3 fracc. XXVIII LNETB.\",\"impacto_comercio\":\"Establece nuevas condiciones para el ejercicio del comercio ambulante: zonas autorizadas, horarios, higiene y presentación. Impacta a aproximadamente 2,400 vendedores ambulantes registrados y no registrados.\",\"observaciones\":\"El proyecto del reglamento se entregará en la siguiente etapa de la propuesta.\",\"presenta_proyecto\":\"0\",\"sujeto_obligado_id\":null,\"sujeto_obligado_nombre\":null}',NULL,NULL,0,1,0,'requiere_air','dictaminada',NULL,1,'2026-06-22 13:04:00','2026-06-23 20:28:54'),(54,NULL,'Reglamento de Comercio Ambulante del Municipio de La Paz, B.C.S.','Reglamento',11,NULL,NULL,'2026-09-22','{\"responsable_nombre\":\"Carlos Méndez Ruiz\",\"responsable_cargo\":\"Enlace de Simplificación\",\"materia\":\"Comercio\",\"sectores_impactados\":\"Comercio informal, vendedores ambulantes, tianguistas, mercados sobre ruedas, ciudadanía consumidora\",\"justificacion\":\"El municipio carece de un instrumento normativo actualizado que regule de manera integral la actividad comercial en vía pública. El reglamento vigente data de 2008 y no contempla las modalidades actuales de comercio ambulante ni los criterios de ordenamiento territorial.\",\"problematica\":\"Existe una proliferación desordenada de puestos ambulantes en zonas turísticas y comerciales que genera conflictos viales, problemas de higiene y competencia desleal con el comercio establecido. La falta de regulación actualizada impide al municipio ordenar esta actividad de manera efectiva.\",\"alternativas\":\"Se evaluaron tres alternativas: 1) Campaña voluntaria de reordenamiento (descartada por falta de mecanismos de cumplimiento), 2) Acuerdo con cámaras de comercio para autorregulación (insuficiente cobertura), 3) Emisión de reglamento municipal (seleccionada por dar certeza jurídica a todas las partes).\",\"beneficios\":\"Ordenamiento del comercio en vía pública, reducción de conflictos viales, mejora de imagen urbana en zonas turísticas, certeza jurídica para vendedores ambulantes, recaudación por permisos.\",\"costos_burocraticos\":\"Se crearán dos trámites nuevos: Permiso de Comercio Ambulante (anual) y Constancia de Ubicación Autorizada. Se estima un costo de $350 por permiso anual.\",\"tramites_impacta\":null,\"acciones_simplificacion\":{\"Reducción de requisitos\":\"Eliminar la constancia de domicilio y aceptar la credencial de elector como comprobante único.\",\"Fusión de trámites y\\/o modalidades\":\"Unificar el permiso actual de venta en vía pública con el nuevo permiso de comercio ambulante, eliminando la duplicidad de trámites.\"},\"acciones_digitalizacion\":{\"Mejorar experiencia de usuario\":\"Habilitar solicitud en línea del permiso anual y mapa digital de ubicaciones autorizadas consultable por la ciudadanía.\"},\"fundamento_juridico\":\"Art. 115 fracc. II Constitución Política de los Estados Unidos Mexicanos; Art. 42 fracc. VI Ley Orgánica del Municipio Libre del Estado de B.C.S.; Art. 3 fracc. XXVIII LNETB.\",\"impacto_comercio\":\"Establece nuevas condiciones para el ejercicio del comercio ambulante: zonas autorizadas, horarios, higiene y presentación. Impacta a aproximadamente 2,400 vendedores ambulantes registrados y no registrados.\",\"observaciones\":\"El proyecto del reglamento se entregará en la siguiente etapa de la propuesta.\",\"presenta_proyecto\":\"0\",\"sujeto_obligado_id\":null,\"sujeto_obligado_nombre\":null}',NULL,NULL,0,1,0,'pendiente','consulta',NULL,1,'2026-06-22 13:12:40','2026-06-22 13:12:40'),(55,'PROP-DGGD-2026-001','Reglamento de Comercio Ambulante del Municipio de La Paz, B.C.S.','Reglamento',11,NULL,NULL,'2026-09-22','{\"responsable_nombre\":\"Carlos Méndez Ruiz\",\"responsable_cargo\":\"Enlace de Simplificación\",\"materia\":\"Comercio\",\"sectores_impactados\":\"Comercio informal, vendedores ambulantes, tianguistas, mercados sobre ruedas, ciudadanía consumidora\",\"justificacion\":\"El municipio carece de un instrumento normativo actualizado que regule de manera integral la actividad comercial en vía pública. El reglamento vigente data de 2008 y no contempla las modalidades actuales de comercio ambulante ni los criterios de ordenamiento territorial.\",\"problematica\":\"Existe una proliferación desordenada de puestos ambulantes en zonas turísticas y comerciales que genera conflictos viales, problemas de higiene y competencia desleal con el comercio establecido. La falta de regulación actualizada impide al municipio ordenar esta actividad de manera efectiva.\",\"alternativas\":\"Se evaluaron tres alternativas: 1) Campaña voluntaria de reordenamiento (descartada por falta de mecanismos de cumplimiento), 2) Acuerdo con cámaras de comercio para autorregulación (insuficiente cobertura), 3) Emisión de reglamento municipal (seleccionada por dar certeza jurídica a todas las partes).\",\"beneficios\":\"Ordenamiento del comercio en vía pública, reducción de conflictos viales, mejora de imagen urbana en zonas turísticas, certeza jurídica para vendedores ambulantes, recaudación por permisos.\",\"costos_burocraticos\":\"Se crearán dos trámites nuevos: Permiso de Comercio Ambulante (anual) y Constancia de Ubicación Autorizada. Se estima un costo de $350 por permiso anual.\",\"tramites_impacta\":null,\"acciones_simplificacion\":{\"Reducción de requisitos\":\"Eliminar la constancia de domicilio y aceptar la credencial de elector como comprobante único.\",\"Fusión de trámites y\\/o modalidades\":\"Unificar el permiso actual de venta en vía pública con el nuevo permiso de comercio ambulante, eliminando la duplicidad de trámites.\"},\"acciones_digitalizacion\":{\"Mejorar experiencia de usuario\":\"Habilitar solicitud en línea del permiso anual y mapa digital de ubicaciones autorizadas consultable por la ciudadanía.\"},\"fundamento_juridico\":\"Art. 115 fracc. II Constitución Política de los Estados Unidos Mexicanos; Art. 42 fracc. VI Ley Orgánica del Municipio Libre del Estado de B.C.S.; Art. 3 fracc. XXVIII LNETB.\",\"impacto_comercio\":\"Establece nuevas condiciones para el ejercicio del comercio ambulante: zonas autorizadas, horarios, higiene y presentación. Impacta a aproximadamente 2,400 vendedores ambulantes registrados y no registrados.\",\"observaciones\":\"El proyecto del reglamento se entregará en la siguiente etapa de la propuesta.\",\"presenta_proyecto\":\"0\",\"sujeto_obligado_id\":null,\"sujeto_obligado_nombre\":null}',NULL,NULL,0,1,0,'exento','consulta',NULL,1,'2026-06-22 13:18:41','2026-06-23 03:59:34'),(56,'PROP-DGGD-2026-002','RECETA DE POZOLE ROJO OFICIAL ORIGINAL','otro',11,NULL,NULL,'2026-06-23','{\"responsable_nombre\":\"Carlos Méndez Ruiz Dig\",\"responsable_cargo\":\"Enlace de Simxxxxxxxxxxxxxxxplificación\",\"materia\":\"El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto. Ingredientes (para 6 porciones) 500 g de maíz pozolero precocido 1 kg de carne de cerdo (espinazo o maciza) 500 g de costilla de cerdo 1 cebolla blanca entera 5 dientes de ajo 2 hojas de laurel Sal al gusto Para la salsa roja: 6 chiles guajillo 4 chiles anchos 1 diente de ajo ¼ de cebolla 1 cucharadita de orégano seco Sal al gusto\",\"sectores_impactados\":\"El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.Ingredientes (para 6 porciones)500 g de maíz pozolero precocido1 kg de carne de cerdo (espinazo o maciza)500 g de costilla de cerdo1 cebolla blanca entera5 dientes de ajo2 hojas de laurelSal al gustoPara la salsa roja:6 chiles guajillo4 chiles anchos1 diente de ajo¼ de cebolla1 cucharadita de orégano secoSal al gusto\",\"justificacion\":\"El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\\r\\nIngredientes (para 6 porciones)\\r\\n500 g de maíz pozolero precocido\\r\\n1 kg de carne de cerdo (espinazo o maciza)\\r\\n500 g de costilla de cerdo\\r\\n1 cebolla blanca entera\\r\\n5 dientes de ajo\\r\\n2 hojas de laurel\\r\\nSal al gusto\\r\\nPara la salsa roja:\\r\\n6 chiles guajillo\\r\\n4 chiles anchos\\r\\n1 diente de ajo\\r\\n¼ de cebolla\\r\\n1 cucharadita de orégano seco\\r\\nSal al gusto\",\"problematica\":\"El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\\r\\nIngredientes (para 6 porciones)\\r\\n500 g de maíz pozolero precocido\\r\\n1 kg de carne de cerdo (espinazo o maciza)\\r\\n500 g de costilla de cerdo\\r\\n1 cebolla blanca entera\\r\\n5 dientes de ajo\\r\\n2 hojas de laurel\\r\\nSal al gusto\\r\\nPara la salsa roja:\\r\\n6 chiles guajillo\\r\\n4 chiles anchos\\r\\n1 diente de ajo\\r\\n¼ de cebolla\\r\\n1 cucharadita de orégano seco\\r\\nSal al gusto\",\"alternativas\":\"El pozole rojo es un platillo tradicional mexicano hecho con maíz pozolero, carne de cerdo y una salsa de chiles guajillo y ancho, acompañado de guarniciones frescas al gusto.\\r\\nIngredientes (para 6 porciones)\\r\\n500 g de maíz pozolero precocido\\r\\n1 kg de carne de cerdo (espinazo o maciza)\\r\\n500 g de costilla de cerdo\\r\\n1 cebolla blanca entera\\r\\n5 dientes de ajo\\r\\n2 hojas de laurel\\r\\nSal al gu