DROP TABLE IF EXISTS `regulaciones`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `regulaciones` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `folio` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nombre` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tipo` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `materia` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dependencia_id` bigint unsigned DEFAULT NULL,
  `fecha_publicacion` date DEFAULT NULL,
  `fecha_vigencia` date DEFAULT NULL,
  `estatus` enum('vigente','en_revision','derogada') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'vigente',
  `archivo_pdf` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `archivo_original` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `archivo_markdown` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `conversion_estatus` enum('pendiente','procesando','listo','error') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pendiente',
  `conversion_error` text COLLATE utf8mb4_unicode_ci,
  `extension_original` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `resumen` text COLLATE utf8mb4_unicode_ci,
  `fundamento_juridico` text COLLATE utf8mb4_unicode_ci,
  `objetivo` text COLLATE utf8mb4_unicode_ci,
  `sector_id` bigint unsigned DEFAULT NULL,
  `palabras_clave` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `deroga_otra` tinyint(1) NOT NULL DEFAULT '0',
  `regulacion_derogada` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `indice` json DEFAULT NULL,
  `estructurada` tinyint(1) NOT NULL DEFAULT '0',
  `created_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `regulaciones_folio_unique` (`folio`),
  KEY `regulaciones_dependencia_id_foreign` (`dependencia_id`),
  KEY `regulaciones_created_by_foreign` (`created_by`),
  KEY `regulaciones_sector_id_foreign` (`sector_id`),
  CONSTRAINT `regulaciones_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `regulaciones_dependencia_id_foreign` FOREIGN KEY (`dependencia_id`) REFERENCES `dependencias` (`id`),
  CONSTRAINT `regulaciones_sector_id_foreign` FOREIGN KEY (`sector_id`) REFERENCES `sectores_scian` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=69 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
