INSERT INTO `regulaciones` VALUES (13,'LPZ-REG-DGGD-2026-001','Reglamento de Protección Civil del Municipio de La Paz, Baja California Sur','Reglamento','Protección Civil',11,'2025-12-19','2026-01-19','vigente',NULL,'regulaciones/originales/13-reglamento-de-proteccion-civil-del-municipio-de-la-paz-baja-california-sur.pdf','regulaciones/markdown/13-reglamento-de-proteccion-civil-del-municipio-de-la-paz-baja-california-sur.md','listo',NULL,'pdf','Este reglamento regula cómo el municipio se organiza para prevenir y responder ante emergencias como huracanes, sismos e incendios. Establece los requisitos para obtener dictámenes de protección civil para negocios y eventos.','Art. 115 fracc. III inciso i) Constitución Política; Art. 8 Ley General de Protección Civil; Art. 12 Ley de Protección Civil del Estado de B.C.S.; Art. 42 fracc. XII Ley Orgánica del Municipio Libre.','Establecer las bases de coordinación, organización y funcionamiento del Sistema Municipal de Protección Civil, así como regular las acciones de prevención, auxilio y recuperación ante fenómenos perturbadores de origen natural o humano en el Municipio de La Paz.',NULL,'protección civil, emergencia, desastre, huracán, sismo, evacuación, dictamen, programa interno',0,NULL,'[{\"linea\": 1, \"nivel\": 1, \"titulo\": \"Reglamento de Protección Civil del Municipio de La Paz, Baja California Sur\"}, {\"linea\": 39, \"nivel\": 3, \"titulo\": \"ARTÍCULO 1.- Las disposiciones emanadas del presente ordenamiento son\"}, {\"linea\": 42, \"nivel\": 3, \"titulo\": \"ARTÍCULO 2.- Este reglamento es de observancia general obligatoria e interés\"}, {\"linea\": 48, \"nivel\": 3, \"titulo\": \"ARTÍCULO 3.- Para el efecto del presente reglamento se entenderá por:\"}, {\"linea\": 110, \"nivel\": 3, \"titulo\": \"ARTÍCULO 4.- Toda persona física o moral dentro del municipio tiene la obligación\"}, {\"linea\": 130, \"nivel\": 3, \"titulo\": \"ARTÍCULO 5.- Las dependencias federales, estatales y municipales, así como sus\"}, {\"l