DROP TABLE IF EXISTS `unidades_valor_referencia`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `unidades_valor_referencia` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `unidad` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `valor_pesos` decimal(14,4) NOT NULL,
  `anio` smallint unsigned NOT NULL,
  `vigencia_inicio` date DEFAULT NULL,
  `vigencia_fin` date DEFAULT NULL,
  `fuente` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT '1',
  `actualizado_por` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unidades_valor_referencia_unidad_anio_unique` (`unidad`,`anio`),
  KEY `unidades_valor_referencia_actualizado_por_foreign` (`actualizado_por`),
  KEY `unidades_valor_referencia_activo_index` (`activo`),
  CONSTRAINT `unidades_valor_referencia_actualizado_por_foreign` FOREIGN KEY (`actualizado_por`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
